// Aggregate all data for Claude AI analysis
const stats = $('Fetch Weekly Dashboard Stats').item.json;
const allAlerts = $('Fetch All Alerts (7 Days)').item.json || [];
const openIncidents = $('Fetch Open Incidents').item.json || [];
const resolvedIncidents = $('Fetch Resolved This Week').item.json || [];

// Weekly alert breakdown by severity
const bySeverity = { CRITICAL: 0, HIGH: 0, MEDIUM: 0, LOW: 0 };
const byType = {};
const byMitre = {};
const attackerIPs = {};

for (const a of allAlerts) {
  if (a.severity) bySeverity[a.severity] = (bySeverity[a.severity] || 0) + 1;
  if (a.type) byType[a.type] = (byType[a.type] || 0) + 1;
  if (a.mitre_technique) byMitre[a.mitre_technique] = (byMitre[a.mitre_technique] || 0) + 1;
  if (a.src_ip) attackerIPs[a.src_ip] = (attackerIPs[a.src_ip] || 0) + 1;
}

// Top attackers
const topAttackers = Object.entries(attackerIPs)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([ip, count]) => ({ ip, count }));

// Top MITRE techniques
const topMitre = Object.entries(byMitre)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([technique, count]) => ({ technique, count }));

// Top threat types
const topTypes = Object.entries(byType)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([type, count]) => ({ type, count }));

// Resolution rate
const totalIncidents = openIncidents.length + resolvedIncidents.length;
const resolutionRate = totalIncidents > 0
  ? Math.round((resolvedIncidents.length / totalIncidents) * 100)
  : 100;

// Risk posture score (0-100, higher = worse)
const riskScore = Math.min(100, Math.round(
  bySeverity.CRITICAL * 10 +
  bySeverity.HIGH * 3 +
  bySeverity.MEDIUM * 0.5 +
  openIncidents.length * 5
));

const riskPosture = riskScore > 70 ? 'CRITICAL RISK'
  : riskScore > 40 ? 'ELEVATED RISK'
  : riskScore > 20 ? 'MODERATE RISK'
  : 'LOW RISK';

const weekOf = new Date();
weekOf.setDate(weekOf.getDate() - 7);
const weekRange = `${weekOf.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – ${new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}`;

return [{ json: {
  stats, bySeverity, topAttackers, topMitre, topTypes,
  openIncidents: openIncidents.length,
  resolvedIncidents: resolvedIncidents.length,
  totalAlerts: allAlerts.length,
  resolutionRate,
  riskScore,
  riskPosture,
  weekRange,
  openIncidentList: openIncidents.slice(0, 5),
  topAttackers,
  topMitre,
}}];

// ── Multi-Provider LLM Call ────────────────────────────────────────────
// Reads LLM_PROVIDER from env: claude | openai | gemini
// Falls back gracefully if provider is unavailable.

const provider = ($env.LLM_PROVIDER || 'claude').toLowerCase();
const prompt   = 'You are the CISO presenting the weekly cybersecurity posture report to the Board. Generate a comprehensive executive-level Weekly Security Board Report.\n\nWeek: ' + $('Aggregate Weekly Metrics').item.json.weekRange + '\nRisk Posture: ' + $('Aggregate Weekly Metrics').item.json.riskPosture + ' (Score: ' + $('Aggregate Weekly Metrics').item.json.riskScore + '/100)\nTotal Alerts: ' + $('Aggregate Weekly Metrics').item.json.totalAlerts + '\nCritical: ' + $('Aggregate Weekly Metrics').item.json.bySeverity.CRITICAL + '\nOpen Incidents: ' + $('Aggregate Weekly Metrics').item.json.openIncidents + '\nResolution Rate: ' + $('Aggregate Weekly Metrics').item.json.resolutionRate + '%\n\nGenerate a board-ready report with: Executive Summary, Risk Posture, Key Metrics, Threat Landscape, Critical Incidents, Security Investments Performance, Compliance Posture, Recommended Board Actions, Outlook Next Week. Tone: Professional, non-technical, business-focused. Under 600 words.';
const maxTok   = 3000;

let apiUrl, headers, body, modelKey;

if (provider === 'openai' || provider === 'gpt') {
  // ── OpenAI ──────────────────────────────────────────────────────────
  const model = $env.OPENAI_MODEL_PRIMARY || $env.LLM_MODEL_PRIMARY || 'gpt-4o';
  apiUrl  = 'https://api.openai.com/v1/chat/completions';
  headers = {
    'Content-Type':  'application/json',
    'Authorization': 'Bearer ' + $env.OPENAI_API_KEY,
  };
  body = JSON.stringify({
    model,
    max_tokens: maxTok,
    messages: [{ role: 'user', content: prompt }],
  });
  modelKey = 'openai:' + model;

} else if (provider === 'gemini' || provider === 'google') {
  // ── Gemini ──────────────────────────────────────────────────────────
  const model = $env.GEMINI_MODEL_PRIMARY || $env.LLM_MODEL_PRIMARY || 'gemini-1.5-pro';
  apiUrl  = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${$env.GOOGLE_API_KEY}`;
  headers = { 'Content-Type': 'application/json' };
  body = JSON.stringify({
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { maxOutputTokens: maxTok },
  });
  modelKey = 'gemini:' + model;

} else {
  // ── Claude (default) ─────────────────────────────────────────────────
  const model = $env.LLM_MODEL_PRIMARY || 'claude-sonnet-4-6';
  apiUrl  = 'https://api.anthropic.com/v1/messages';
  headers = {
    'Content-Type':      'application/json',
    'x-api-key':         $env.ANTHROPIC_API_KEY,
    'anthropic-version': '2023-06-01',
  };
  body = JSON.stringify({
    model,
    max_tokens: maxTok,
    messages: [{ role: 'user', content: prompt }],
  });
  modelKey = 'claude:' + model;
}

// Make the HTTP call
const resp = await $helpers.httpRequest({
  method:  'POST',
  url:     apiUrl,
  headers: headers,
  body:    body,
});

// ── Extract text from provider-specific response format ───────────────
let responseText = '';
if (provider === 'openai' || provider === 'gpt') {
  responseText = resp.choices?.[0]?.message?.content || '';
} else if (provider === 'gemini' || provider === 'google') {
  responseText = resp.candidates?.[0]?.content?.parts?.[0]?.text || '';
} else {
  responseText = resp.content?.[0]?.text || '';
}

return [{ json: { responseText, modelKey, provider } }];

const metrics = $('Aggregate Weekly Metrics').item.json;
const reportText = $('AI: Generate Board Report (Multi-Provider)').item.json?.responseText || 'Report generation failed';

const riskColor = {
  'CRITICAL RISK': 'danger',
  'ELEVATED RISK': 'warning',
  'MODERATE RISK': 'good',
  'LOW RISK': 'good'
}[metrics.riskPosture] || 'warning';

const riskEmoji = {
  'CRITICAL RISK': '🔴',
  'ELEVATED RISK': '🟠',
  'MODERATE RISK': '🟡',
  'LOW RISK': '🟢'
}[metrics.riskPosture] || '⚠️';

// Format top MITRE as table rows
const mitreRows = metrics.topMitre
  .map(m => `• ${m.technique}: ${m.count} occurrences`)
  .join('\n');

// Format top attackers
const attackerRows = metrics.topAttackers
  .map((a, i) => `${i+1}. ${a.ip} — ${a.count} alerts`)
  .join('\n');

return [{ json: {
  ...metrics,
  reportText,
  riskColor,
  riskEmoji,
  mitreRows,
  attackerRows,
  reportDate: new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
} }];

