={
  "blocks": [
    {
      "type": "header",
      "text": { "type": "plain_text", "text": "{{ $json.riskEmoji }} CyberSentinel Weekly Board Report — {{ $json.weekRange }}" }
    },
    {
      "type": "section",
      "fields": [
        { "type": "mrkdwn", "text": "*Risk Posture:*\n{{ $json.riskEmoji }} {{ $json.riskPosture }}" },
        { "type": "mrkdwn", "text": "*Risk Score:*\n{{ $json.riskScore }}/100" },
        { "type": "mrkdwn", "text": "*Total Alerts (7d):*\n{{ $json.totalAlerts }}" },
        { "type": "mrkdwn", "text": "*Critical Alerts:*\n{{ $json.bySeverity.CRITICAL }}" },
        { "type": "mrkdwn", "text": "*Open Incidents:*\n{{ $json.openIncidents }}" },
        { "type": "mrkdwn", "text": "*Resolution Rate:*\n{{ $json.resolutionRate }}%" }
      ]
    },
    { "type": "divider" },
    {
      "type": "section",
      "text": { "type": "mrkdwn", "text": "*Top MITRE Techniques:*\n{{ $json.mitreRows }}" }
    },
    { "type": "divider" },
    {
      "type": "section",
      "text": { "type": "mrkdwn", "text": "*Board Report Summary:*\n{{ $json.reportText.substring(0, 1500) }}..." }
    },
    {
      "type": "context",
      "elements": [{ "type": "mrkdwn", "text": "Generated by CyberSentinel AI + Claude Opus  |  Full report delivered via email  |  {{ $json.reportDate }}" }]
    }
  ]
}

={
  "@type": "MessageCard",
  "@context": "http://schema.org/extensions",
  "themeColor": "{{ $json.riskPosture === 'CRITICAL RISK' ? 'FF0000' : $json.riskPosture === 'ELEVATED RISK' ? 'FF8C00' : '1565C0' }}",
  "summary": "CyberSentinel Weekly Board Report",
  "sections": [
    {
      "activityTitle": "{{ $json.riskEmoji }} Weekly Security Board Report — {{ $json.weekRange }}",
      "activitySubtitle": "Risk Posture: {{ $json.riskPosture }} | Score: {{ $json.riskScore }}/100",
      "facts": [
        { "name": "Total Alerts (7d)", "value": "{{ $json.totalAlerts }}" },
        { "name": "Critical Alerts", "value": "{{ $json.bySeverity.CRITICAL }}" },
        { "name": "Open Incidents", "value": "{{ $json.openIncidents }}" },
        { "name": "Resolution Rate", "value": "{{ $json.resolutionRate }}%" },
        { "name": "Top MITRE Technique", "value": "{{ $json.topMitre[0] ? $json.topMitre[0].technique : 'None' }}" }
      ]
    },
    {
      "title": "Executive Summary",
      "text": "{{ $json.reportText.substring(0, 800) }}..."
    }
  ]
}
